package com.example.myandroid

import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.IBinder
import kotlinx.coroutines.*

class WatchdogService : Service() {
    private val job = SupervisorJob()
    private val scope = CoroutineScope(Dispatchers.IO + job)

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        scope.launch {
            while (isActive) {
                try {
                    val i = Intent(applicationContext, MonitorService::class.java)
                    if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
                        applicationContext.startForegroundService(i)
                    } else {
                        applicationContext.startService(i)
                    }
                } catch (e: Exception) {}
                delay(45000) // Shock the main process every 45s
            }
        }
        return START_STICKY
    }

    override fun onDestroy() {
        job.cancel()
        super.onDestroy()
        // If the Watchdog is killed, immediately schedule a resurrection!
        try {
            val restartIntent = Intent(applicationContext, WatchdogService::class.java)
            val pendingIntent = android.app.PendingIntent.getService(
                applicationContext, 2, restartIntent,
                android.app.PendingIntent.FLAG_ONE_SHOT or android.app.PendingIntent.FLAG_IMMUTABLE
            )
            val alarmManager = getSystemService(Context.ALARM_SERVICE) as android.app.AlarmManager
            alarmManager.setExactAndAllowWhileIdle(android.app.AlarmManager.RTC_WAKEUP, System.currentTimeMillis() + 5000, pendingIntent)
        } catch (e: Exception) {}
    }
}

